def trie_ops(operations):
    class TrieNode:
        __slots__ = ("children", "is_word")

        def __init__(self):
            self.children = {}
            self.is_word = False

    class Trie:
        def __init__(self):
            self.root = TrieNode()

        def insert(self, word):
            node = self.root
            for ch in word:
                if ch not in node.children:
                    node.children[ch] = TrieNode()
                node = node.children[ch]
            node.is_word = True

        def _find(self, s):
            node = self.root
            for ch in s:
                if ch not in node.children:
                    return None
                node = node.children[ch]
            return node

        def search(self, word):
            node = self._find(word)
            return node is not None and node.is_word

        def startsWith(self, prefix):
            return self._find(prefix) is not None

    results = []
    trie = None
    for op in operations:
        method, args = op[0], op[1:]
        if method == "Trie":
            trie = Trie()
            results.append(None)
        elif method == "insert":
            trie.insert(*args)
            results.append(None)
        elif method == "search":
            results.append(trie.search(*args))
        elif method == "startsWith":
            results.append(trie.startsWith(*args))
    return results
